package github.chains;

import spoon.Launcher;
import spoon.reflect.CtModel;
import spoon.reflect.declaration.CtClass;
import spoon.reflect.declaration.CtConstructor;
import spoon.reflect.declaration.CtImport;
import spoon.reflect.declaration.CtMethod;
import spoon.reflect.declaration.CtType;
import spoon.reflect.factory.Factory;
import spoon.reflect.reference.CtReference;
import spoon.reflect.visitor.filter.TypeFilter;
import spoon.support.reflect.code.CtNewClassImpl;
import java.util.List;
import java.util.ArrayList;

public class Main {
    public static void main(String[] args) {
        // Create a Spoon launcher
        Launcher launcher = new Launcher();

        // Set the source directory to process
        launcher.addInputResource("/workspace/XChange");

        // Set the output directory
        launcher.setSourceOutputDirectory("/workspace/XChange-output");

        // Build the model
        CtModel model = launcher.buildModel();

        Factory factory = model.getFactory();

        // Fix 1: Replace PNConfiguration() constructor calls with PNConfiguration(userId)
        // Find all new PNConfiguration() calls
        model.getElements(new TypeFilter<CtNewClassImpl>(CtNewClassImpl.class)).forEach(newClass -> {
            if (newClass.getType() != null && 
                newClass.getType().getQualifiedName().equals("com.pubnub.api.PNConfiguration")) {

                // Check if it's a no-arg constructor call
                if (newClass.getArguments().isEmpty()) {
                    // Create a new constructor call with a UserId parameter
                    // We'll use a placeholder UserId for now, but in a real-world scenario
                    // this would need to be handled more intelligently
                    try {
                        CtClass<?> pnConfigurationClass = factory.Type().get("com.pubnub.api.PNConfiguration");
                        if (pnConfigurationClass != null) {
                            // Find the constructor that takes UserId
                            for (CtConstructor<?> constructor : pnConfigurationClass.getConstructors()) {
                                if (constructor.getParameters().size() == 1 && 
                                    constructor.getParameters().get(0).getType().getQualifiedName().equals("com.pubnub.api.UserId")) {
                                    // Replace the constructor call
                                    newClass.setArguments(factory.Code().createInvocation(
                                        factory.Code().createTypeAccess(factory.Type().createReference("com.pubnub.api.UserId")),
                                        "new",
                                        factory.Code().createLiteral("defaultUserId")
                                    ).getArguments());
                                    break;
                                }
                            }
                        }
                    } catch (Exception e) {
                        // Log error but continue processing
                        System.err.println("Error fixing PNConfiguration constructor: " + e.getMessage());
                    }
                }
            }
        });

        // Fix 2: Remove imports for missing classes
        List<CtImport> importsToRemove = new ArrayList<>();
        model.getElements(new TypeFilter<CtImport>(CtImport.class)).forEach(importDecl -> {
            String importedType = importDecl.getReference().getQualifiedName();
            if (importedType.equals("com.pubnub.api.models.consumer.pubsub.objects.PNMembershipResult") ||
                importedType.equals("com.pubnub.api.models.consumer.pubsub.objects.PNSpaceResult") ||
                importedType.equals("com.pubnub.api.models.consumer.pubsub.objects.PNUserResult")) {
                importsToRemove.add(importDecl);
            }
        });

        // Remove the imports
        importsToRemove.forEach(importDecl -> {
            importDecl.delete();
        });

        // Fix 3: Remove method overrides for missing callback methods
        // Find all SubscribeCallback implementations
        model.getElements(new TypeFilter<CtClass<?>>(CtClass.class)).forEach(clazz -> {
            if (clazz.getSuperclass() != null && 
                clazz.getSuperclass().getQualifiedName().equals("com.pubnub.api.callbacks.SubscribeCallback")) {

                // Remove the user, space, and membership method overrides
                clazz.getMethods().removeIf(method -> {
                    return (method.getSimpleName().equals("user") ||
                           method.getSimpleName().equals("space") ||
                           method.getSimpleName().equals("membership"));
                });
            }
        });

        // Generate the modified code
        launcher.setSourceOutputDirectory("/workspace/XChange-output");
        launcher.process();

        System.out.println("Transformation completed successfully!");
    }
}

