        model.getElements(new TypeFilter<CtImport>(CtImport.class)).forEach(importDecl -> {
            String importedType = importDecl.getReference().toString();
            if (importedType.equals("com.pubnub.api.models.consumer.pubsub.objects.PNMembershipResult") ||
                importedType.equals("com.pubnub.api.models.consumer.pubsub.objects.PNSpaceResult") ||
                importedType.equals("com.pubnub.api.models.consumer.pubsub.objects.PNUserResult")) {
                importsToRemove.add(importDecl);
