                public void signal(PubNub pubnub, PNSignalResult pnSignalResult) {
                  LOG.debug("PubNub signal: {}", pnSignalResult.toString());
                }

                @Override
                public void file(PubNub pubnub, PNFileEventResult pnFileEventResult) {
                  // Empty implementation - this method was added in pubnub-gson 6.3.2
                  // but we don't use file features in this service
                  LOG.debug("PubNub file event: {}", pnFileEventResult.toString());
                }

